export function nextGeneration(cells: [number, number][]): [number, number][] {
  const alive = new Set(cells.map(([x, y]) => `${x},${y}`));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }

  const result: [number, number][] = [];
  for (const [key, count] of neighborCounts) {
    const [x, y] = key.split(",").map(Number);
    if (alive.has(key) && (count === 2 || count === 3)) {
      result.push([x, y]);
    } else if (!alive.has(key) && count === 3) {
      result.push([x, y]);
    }
  }

  return result;
}
```

Review for Simple Design Rules. One thing to consider: the two conditions in the loop can be simplified. A cell lives in the next generation if:
- count === 3 (alive or dead, doesn't matter), OR
- count === 2 AND cell is alive

So the condition could be: `count === 3 || (count === 2 && alive.has(key))`

Apply this simplification if it improves readability. Run `pnpm test` to confirm all tests still pass.

EXPERIMENT MODE: Run autonomously.

